trigger.body:
	vCheck NUMBER;
BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

	IF TG_OP IN ('DELETE') THEN

		SELECT COUNT(*) INTO vCheck 
		FROM scrvro_route_week WHERE
		scrvro_route_period_id!=:old.scrvro_route_period_id ;

		IF vCheck > 0 THEN
			RAISE_APPLICATION_ERROR(-20000, 'El periódo no pude ser eliminado') ;
		END IF;
	END IF;

	END SCRVRO_ROUTE_PERIOD_3_TRG
